import torch

from diffusers import CosineAnnealingScheduler

from .test_schedulers import SchedulerCommonTest


class CosineAnnealingSchedulerTest(SchedulerCommonTest):
    scheduler_classes = (CosineAnnealingScheduler,)

    def get_scheduler_config(self, **kwargs):
        config = {
            "num_train_timesteps": 1000,
            "beta_start": 0.0001,
            "beta_end": 0.02,
            "prediction_type": "epsilon",
            "clip_sample": True,
        }
        config.update(**kwargs)
        return config

    def test_timesteps(self):
        for timesteps in [1, 5, 100, 1000]:
            self.check_over_configs(num_train_timesteps=timesteps)

    def test_betas(self):
        for beta_start, beta_end in zip([0.0001, 0.001, 0.01], [0.002, 0.02, 0.2]):
            self.check_over_configs(beta_start=beta_start, beta_end=beta_end)

    def test_betas_are_cosine(self):
        """Betas should follow cosine annealing pattern and all be non-negative."""
        scheduler_config = self.get_scheduler_config()
        scheduler = CosineAnnealingScheduler(**scheduler_config)
        betas = scheduler.betas.numpy()
        assert len(betas) == 1000
        assert betas[0] >= 0
        assert betas[-1] >= 0
        # All betas must be positive (required for alphas_cumprod to be monotonically decreasing)
        assert (betas > 0).all()

    def test_alphas_cumprod_decreasing(self):
        """Cumulative product of alphas should be monotonically decreasing."""
        scheduler_config = self.get_scheduler_config()
        scheduler = CosineAnnealingScheduler(**scheduler_config)
        alphas_cumprod = scheduler.alphas_cumprod.numpy()
        for i in range(1, len(alphas_cumprod)):
            assert alphas_cumprod[i] <= alphas_cumprod[i - 1] + 1e-6

    def test_prediction_type(self):
        for prediction_type in ["epsilon", "sample", "v_prediction"]:
            self.check_over_configs(prediction_type=prediction_type)

    def test_clip_sample(self):
        for clip_sample in [True, False]:
            self.check_over_configs(clip_sample=clip_sample)

    def test_time_indices(self):
        for t in [0, 500, 999]:
            self.check_over_forward(time_step=t)

    def test_timestep_spacing(self):
        for spacing in ["linspace", "leading", "trailing"]:
            self.check_over_configs(timestep_spacing=spacing)

    def test_full_loop_no_noise(self):
        scheduler_config = self.get_scheduler_config()
        scheduler = CosineAnnealingScheduler(**scheduler_config)

        num_trained_timesteps = len(scheduler)
        model = self.dummy_model()
        sample = self.dummy_sample_deter

        scheduler.set_timesteps(num_trained_timesteps)

        for t in scheduler.timesteps:
            residual = model(sample, t)
            output = scheduler.step(residual, t, sample)
            sample = output.prev_sample

        result_mean = torch.mean(torch.abs(sample))
        assert abs(result_mean.item()) < 1e1, f"result_mean too large: {result_mean.item()}"

